// HWC Notification Router with Deduplication
// Normalizes incoming notifications and routes to appropriate Slack channel
// Includes rate limiting and deduplication

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Initialize dedup cache
if (!staticData.recentNotifications) {
  staticData.recentNotifications = {};
}

const now = Date.now();
const DEDUP_WINDOW = 5 * 60 * 1000; // 5 minute dedup window
const RATE_LIMIT_WINDOW = 60 * 1000; // 1 minute rate limit window
const MAX_PER_MINUTE = 10; // Max notifications per minute

// Clean old entries
Object.keys(staticData.recentNotifications).forEach(key => {
  if (now - staticData.recentNotifications[key].timestamp > DEDUP_WINDOW) {
    delete staticData.recentNotifications[key];
  }
});

// Default values
const defaults = {
  channel: '#hwc-system',
  severity: 'info',
  service: 'unknown',
  domain: 'system'
};

// Channel routing rules
const channelMap = {
  'media': '#hwc-media',
  'arr': '#hwc-media',
  'download': '#hwc-media',
  'surveillance': '#hwc-alerts',
  'security': '#hwc-alerts',
  'alert': '#hwc-alerts',
  'error': '#hwc-alerts',
  'critical': '#hwc-alerts',
  'ai': '#hwc-system',
  'finance': '#hwc-system',
  'documents': '#hwc-system',
  'books': '#hwc-media',
  'system': '#hwc-system',
  'infrastructure': '#hwc-system',
  'monitoring': '#hwc-system'
};

// Severity to emoji mapping
const severityEmoji = {
  'critical': ':rotating_light:',
  'error': ':x:',
  'warning': ':warning:',
  'success': ':white_check_mark:',
  'info': ':information_source:'
};

// Extract and normalize fields
const title = input.title || input.subject || 'Notification';
const message = input.message || input.body || input.text || '';
const severity = input.severity || input.level || defaults.severity;
const service = input.service || input.source || defaults.service;
const domain = input.domain || input.category || defaults.domain;
const timestamp = input.timestamp || new Date().toISOString();
const metadata = input.metadata || input.data || {};
const dedupKey = input.dedupKey || `${service}:${title}:${severity}`;

// Check for duplicate
const isDuplicate = staticData.recentNotifications[dedupKey] && 
  (now - staticData.recentNotifications[dedupKey].timestamp < DEDUP_WINDOW);

// Rate limiting check
const recentCount = Object.values(staticData.recentNotifications)
  .filter(n => now - n.timestamp < RATE_LIMIT_WINDOW).length;
const isRateLimited = recentCount >= MAX_PER_MINUTE && severity !== 'critical';

if (isDuplicate) {
  return {
    json: {
      skipped: true,
      reason: 'duplicate',
      dedupKey,
      message: 'Duplicate notification within 5 minutes'
    }
  };
}

if (isRateLimited) {
  return {
    json: {
      skipped: true,
      reason: 'rate_limited',
      message: `Rate limit exceeded (${recentCount}/${MAX_PER_MINUTE} per minute)`
    }
  };
}

// Record this notification
staticData.recentNotifications[dedupKey] = {
  timestamp: now,
  title,
  service
};

// Determine channel
let channel = input.channel || channelMap[domain.toLowerCase()] || defaults.channel;
if (severity === 'critical' || severity === 'error') {
  channel = '#hwc-alerts';
}

// Build Slack blocks
const emoji = severityEmoji[severity] || ':bell:';
const blocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `${emoji} ${title}`,
      emoji: true
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Service:*\n${service}` },
      { type: 'mrkdwn', text: `*Severity:*\n${severity.toUpperCase()}` }
    ]
  }
];

if (message) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: message.substring(0, 3000) }
  });
}

// Add metadata fields if present
if (Object.keys(metadata).length > 0) {
  const metaFields = Object.entries(metadata).slice(0, 4).map(([k, v]) => ({
    type: 'mrkdwn',
    text: `*${k}:*\n${String(v).substring(0, 200)}`
  }));
  blocks.push({ type: 'section', fields: metaFields });
}

// Add timestamp footer
blocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `Sent at ${new Date(timestamp).toLocaleString('en-US', { timeZone: 'America/Denver' })}`
  }]
});

return {
  json: {
    skipped: false,
    channel,
    text: `${emoji} [${service}] ${title}`,
    blocks,
    severity,
    service,
    domain,
    dedupKey
  }
};

// Fallback to ntfy if Slack fails
const input = $input.first().json;

if (input.error) {
  // Slack failed, try ntfy
  return {
    json: {
      useFallback: true,
      ntfyPayload: {
        topic: 'hwc-alerts',
        title: input.text || 'HWC Notification',
        message: 'Slack notification failed, sent via ntfy',
        priority: input.severity === 'critical' ? 5 : 3
      },
      originalError: input.error
    }
  };
}

return { json: { useFallback: false, success: true, ...input } };
